import unittest

class TestMultiplyFunction(unittest.TestCase):
    def test_multiply(self):
        self.assertEqual(multiply("123", "456"), "56088")
        self.assertEqual(multiply("0", "123"), "0")
        self.assertEqual(multiply("123", "0"), "0")
        self.assertEqual(multiply("999", "999"), "998001")
        self.assertEqual(multiply("123456789", "987654321"), "121932631112635269")
        self.assertEqual(multiply("111111111", "111111111"), "12345678987654321")
        self.assertEqual(multiply("1000000000", "1000000000"), "1000000000000000000")
